const stuecke = $('NocoDB: Ausrüstungsstücke laden').first().json.list || [];
const typen = $('NocoDB: Ausrüstungstypen laden').first().json.list || [];
const waescheList = $input.first().json.list || [];

const maxMap = {};
for (const t of typen) {
  if (t.Bezeichnung && t.Max_Waeschen) maxMap[t.Bezeichnung] = t.Max_Waeschen;
}

const countMap = {};
for (const w of waescheList) {
  const id = w.Ausruestungstueck_Id;
  if (id) countMap[id] = (countMap[id] || 0) + 1;
}

const THRESHOLD = 0.9;
const items = stuecke
  .filter(a => {
    const max = maxMap[a.Ausruestungstyp];
    if (!max) return false;
    const count = countMap[a.Id] || 0;
    return count >= max * THRESHOLD;
  })
  .map(a => {
    const max = maxMap[a.Ausruestungstyp];
    const count = countMap[a.Id] || 0;
    const pct = Math.round(count / max * 100);
    return { ...a, _count: count, _max: max, _pct: pct };
  })
  .sort((a, b) => b._pct - a._pct);

if (items.length === 0) {
  return [{ json: { anzahl: 0, betreff: '', html: '' } }];
}

const atLimit = items.filter(a => a._pct >= 100).length;
const betreff = atLimit > 0
  ? 'PSA: ' + atLimit + ' Stueck Waeschlimit erreicht + ' + (items.length - atLimit) + ' naehern sich dem Limit'
  : 'PSA: ' + items.length + ' Stueck naehern sich dem Waeschlimit (>=90%)';

const rows = items.map(a => {
  const color = a._pct >= 100 ? '#ef4444' : '#f97316';
  return '<tr>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Seriennummer || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Ausruestungstyp || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb">' + (a.Kamerad || '-') + '</td>'
    + '<td style="padding:8px;border-bottom:1px solid #e5e7eb;color:' + color + ';font-weight:600">' + a._count + ' / ' + a._max + ' (' + a._pct + '%)</td>'
    + '</tr>';
}).join('');

const html = '<html><body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#111827">'
  + '<h2 style="margin-top:0;color:#1e3a5f">PSA-Waeschlimit-Reminder</h2>'
  + '<p>Folgende Ausruestungsstuecke haben 90% oder mehr ihrer maximalen Waesche-Zyklen erreicht:</p>'
  + '<table style="width:100%;border-collapse:collapse;font-size:14px">'
  + '<thead><tr style="background:#f3f4f6;text-align:left">'
  + '<th style="padding:8px">Seriennummer</th>'
  + '<th style="padding:8px">Typ</th>'
  + '<th style="padding:8px">Kamerad</th>'
  + '<th style="padding:8px">Waeschen</th>'
  + '</tr></thead>'
  + '<tbody>' + rows + '</tbody>'
  + '</table>'
  + '<p style="margin-top:24px;font-size:12px;color:#6b7280">Dieser Reminder wird automatisch jeden Montag versandt.<br>'
  + '<a href="https://IHRE-PSA-URL" style="color:#3b82f6">PSA-Verwaltung oeffnen</a></p>'
  + '</body></html>';

return [{ json: { anzahl: items.length, betreff, html } }];
